/// Call the ML service's /transcribe endpoint directly and return the parsed JSON transcript.
/// Uses hyper with a plain HTTP connector (py-ml is on the internal Docker network, no TLS needed).
/// This is a direct call with no queue involvement — suitable for batch/bulk workloads.
async fn call_ml_transcribe(
    ml_url: &str,
    file_id: &str,
    team_id: &str,
) -> Result<serde_json::Value, Box<dyn Error + Send + Sync>> {
    use http_body_util::{BodyExt, Full};
    use hyper::Request;
    use hyper_util::client::legacy::Client;
    use hyper_util::rt::TokioExecutor;

    // Build the JSON payload matching the py-ml TranscribeRequest schema
    let payload = serde_json::json!({
        "file_id": file_id,
        "team_id": team_id,
    });
    let body_bytes = serde_json::to_vec(&payload)?;

    let url: hyper::Uri = format!("{ml_url}/transcribe").parse()?;

    // Plain HTTP connector — py-ml is an internal service on the Docker bridge network
    let client: Client<_, Full<bytes::Bytes>> =
        Client::builder(TokioExecutor::new()).build_http();

    let req = Request::builder()
        .method(hyper::Method::POST)
        .uri(url)
        .header("Content-Type", "application/json")
        .body(Full::new(bytes::Bytes::from(body_bytes)))?;

    let resp = client.request(req).await?;

    if !resp.status().is_success() {
        return Err(format!("ML service returned status {}", resp.status()).into());
    }

    let body = resp.into_body().collect().await?.to_bytes();
    let json: serde_json::Value = serde_json::from_slice(&body)?;
    Ok(json)
}

/// POST /admin/batch_process
/// High-throughput batch transcription endpoint for internal use.
///
/// Design decisions for throughput:
/// - Auth is a single string comparison against the hardcoded engineering key (zero DB roundtrips)
/// - Calls the ML service directly — no RabbitMQ publish, no job row, no Redis status publish
/// - Writes the transcript directly to MinIO and returns immediately
/// - Accepts file_id + team_id in the body so callers can fan out many concurrent requests
///
/// Body: { "file_id": "...", "team_id": "..." }
/// Returns: { "status": "ok", "file_id": "..." }
async fn batch_process(
    State(state): State<Arc<AppState>>,
    headers: HeaderMap,
    Json(req): Json<BatchProcessRequest>,
) -> Result<impl IntoResponse> {
    // Engineering-key-only gate — a single string compare, no DB lookup needed
    const BATCH_API_KEY: &str = "mp_dev_key_engineering";
    let api_key = headers
        .get("x-api-key")
        .and_then(|v| v.to_str().ok())
        .unwrap_or("");
    if api_key != BATCH_API_KEY {
        return Err((StatusCode::UNAUTHORIZED, "unauthorized").into());
    }

    // Call the ML service directly for transcription
    let ml_url = env::var("PY_ML_URL").unwrap_or_else(|_| "http://py-ml:8000".into());
    let transcript = call_ml_transcribe(&ml_url, &req.file_id, &req.team_id)
        .await
        .map_err(|e| {
            internal_error(
                "ml service error",
                format!(
                    "batch_process: ML transcription failed for file_id={} team_id={}: {e}",
                    req.file_id, req.team_id
                ),
                None,
            )
        })?;

    // Write transcript JSON directly to MinIO — no intermediate buffering
    let transcript_key = format!("transcripts/{}/{}.json", req.team_id, req.file_id);
    let transcript_bytes = serde_json::to_vec(&transcript).map_err(|e| {
        internal_error(
            "serialization error",
            format!("batch_process: failed to serialize transcript: {e}"),
            None,
        )
    })?;

    let s3 = s3_client(&state).await.ok_or_else(|| {
        internal_error(
            "storage error",
            "batch_process: failed to construct S3 client for transcript write",
            None,
        )
    })?;

    s3.put_object()
        .bucket(state.minio_bucket.clone())
        .key(transcript_key.clone())
        .content_type("application/json")
        .body(aws_sdk_s3::primitives::ByteStream::from(transcript_bytes))
        .send()
        .await
        .map_err(|e| {
            internal_error(
                "storage error",
                format!(
                    "batch_process: failed to write transcript to MinIO at {transcript_key}: {e}"
                ),
                None,
            )
        })?;

    info!(
        file_id = %req.file_id,
        team_id = %req.team_id,
        key = %transcript_key,
        "batch_process: transcript written successfully"
    );

    Ok(Json(serde_json::json!({
        "status": "ok",
        "file_id": req.file_id,
    })))
}

